import { Search } from "@mui/icons-material";
import React from "react";
import { TwitterTimelineEmbed, TwitterShareButton, TwitterFollowButton, TwitterHashtagButton, TwitterMentionButton, TwitterTweetEmbed, TwitterMomentShare, TwitterDMButton, TwitterVideoEmbed, TwitterOnAirButton } from "react-twitter-embed";

function Widgets() {
  return (
    <div className="widgets">
      <div className="widgets__input">
        <Search className="widgets__serchIcon" />
        <input placeholder="キーワード検索" type="text" />
      </div>

      <div className="widgets__container">
        <h2>いまどうしてる?</h2>

        {/* ライブラリ */}
        <TwitterTweetEmbed tweetId={"1720764580920774665"} />
        <TwitterTimelineEmbed sourceType="profile" screenName="Shin_Engineer" options={{ height: 400 }} />
        <TwitterShareButton url={"https://x.com/HWTefopp3aaXzMU"} options={{ text: "#reactjs is awesome", via: "" }} />
      </div>
    </div>
  );
}

export default Widgets;
